def word_cloud(text):
    counts = {}
    for word in text.lower().split():
        word = word.strip('.,!?;:"\'()-')
        if word:
            counts[word] = counts.get(word, 0) + 1
    return counts

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_sentence(self):
        result = word_cloud("The cat sat on the mat")
        self.assertEqual(result, {"the": 2, "cat": 1, "sat": 1, "on": 1, "mat": 1})

    def test_case_insensitive_with_punctuation(self):
        result = word_cloud("Hello, hello! HELLO.")
        self.assertEqual(result, {"hello": 3})

    def test_empty_string(self):
        result = word_cloud("")
        self.assertEqual(result, {})

    def test_hidden_single_word(self):
        result = word_cloud("One")
        self.assertEqual(result, {"one": 1})

    def test_hidden_repeated_word(self):
        result = word_cloud("word word word")
        self.assertEqual(result, {"word": 3})

    def test_hidden_all_same_case_variants(self):
        result = word_cloud("A a A a A")
        self.assertEqual(result, {"a": 5})

    def test_hidden_heavy_punctuation(self):
        result = word_cloud("Hello... World!!!")
        self.assertEqual(result, {"hello": 1, "world": 1})

    def test_hidden_book_excerpt(self):
        text = "It was the best of times, it was the worst of times."
        result = word_cloud(text)
        expected = {"it": 2, "was": 2, "the": 2, "best": 1, "of": 2, "times": 2, "worst": 1}
        self.assertEqual(result, expected)

if __name__ == '__main__':
    unittest.main()
